package com.vladdrummer.prayerkmp.feature.strings

internal object PrayerStringsMap {
    val values: Map<String, String> = mapOf(
        "AcafistIiSusuSladchaishemu" to "<h2><font color=\"#aa2c2c\">Акафист Иисусу Сладчайшему</h2><br /><br /></font>\n\n<b><font color=\"#aa2c2c\">Кондак 1</font></b><br /><br />\n<font color=\"#aa2c2c\">В</font>озбра́нный Воево́до и Го́споди, а́да победи́телю, \nя́ко изба́влься от ве́чныя сме́рти, похва́льная воспису́ю \nТи, созда́ние и раб Твой; но, я́ко име́яй милосе́рдие \nнеизрече́нное, от вся́ких мя бед свободи́, зову́ща: Иису́се, \nСы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 1</font></b><br /><br />\n<font color=\"#aa2c2c\">А́</font>нгелов Тво́рче и Го́споди Сил, отве́рзи \nми недоуме́нный ум и язы́к на похвалу́ пречи́стаго \nТвоего́ и́мене, я́коже глухо́му и гугни́вому дре́вле \nслух и язы́к отве́рзл еси́́, и, глаго́лаше, зовы́й \nтакова́я:<br />\n\n<font color=\"#aa2c2c\">И</font>ису́се пречу́дный, А́нгелов удивле́ние; <br />\n<font color=\"#aa2c2c\">И</font>ису́се преси́́льный, прароди́телей избавле́ние. <br /> \n<font color=\"#aa2c2c\">И</font>ису́се пресла́дкий, патриа́рхов велича́ние; <br />\n<font color=\"#aa2c2c\">И</font>ису́се пресла́вный, царе́й укрепле́ние. <br />\n<font color=\"#aa2c2c\">И</font>ису́се прелюби́мый, проро́ков исполне́ние; <br />\n<font color=\"#aa2c2c\">И</font>ису́се преди́вный, му́чеников кре́посте. <br />\n<font color=\"#aa2c2c\">И</font>ису́се прети́хий, мона́хов ра́досте; <br />\n<font color=\"#aa2c2c\">И</font>ису́се преми́лостивый, пресви́теров сла́досте. <br /> \n<font color=\"#aa2c2c\">И</font>ису́се премилосе́рдый, по́стников воздержа́ние; <br />\n<font color=\"#aa2c2c\">И</font>ису́се пресла́достный, преподо́бных ра́дование. <br />\n<font color=\"#aa2c2c\">И</font>ису́се пречестны́й, де́вственных целому́дрие; <br />\n<font color=\"#aa2c2c\">И</font>ису́се предве́чный, гре́шников спасе́ние. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 2</font></b><br /><br />\n<font color=\"#aa2c2c\">В</font>и́дя вдови́цу зе́льне пла́чущу, Го́споди, \nя́коже бо тогда́ умилосе́рдився, сы́на ея́ на \nпогребе́ние несо́ма воскреси́́л еси́́; си́це и о мне \nумилосе́рдися, Человеколю́бче, и грехми́ умерщвле́нную мою́ \nду́шу воскреси́́, зову́щую: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 2</font></b><br /><br />\n<font color=\"#aa2c2c\">Р</font>а́зум неуразуме́нный \nразуме́ти Фили́пп ищя́, Го́споди, покажи́ нам Отца́, \nглаго́лаше. Ты же к нему́: толи́кое вре́мя сый со \nМно́ю, не позна́л ли еси́́, я́ко Оте́ц во Мне, и \nАз во Отце́ есмь? Те́мже, Неизсле́дованне, со стра́хом \nзову́ Ти:<br /> \n\n<font color=\"#aa2c2c\">И</font>ису́се, Бо́же предве́чный;<br /> \n<font color=\"#aa2c2c\">И</font>ису́се, Царю́ преси́́льный. <br /> \n<font color=\"#aa2c2c\">И</font>ису́се, Влады́ко долготерпели́вый; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Спа́се преми́лостивый. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, храни́телю мой преблаги́й;  <br />\n<font color=\"#aa2c2c\">И</font>ису́се, очи́сти грехи́ моя́.<br />\n<font color=\"#aa2c2c\">И</font>ису́се, отыми́ беззако́ния моя́; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, отпусти́ непра́вды моя́. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, надеждо́ моя́, не оста́ви мене́́; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, помо́щниче мой, не отри́ни мене́́.<br />\n<font color=\"#aa2c2c\">И</font>ису́се, Созда́телю мой, не забу́ди мене́́;<br />\n<font color=\"#aa2c2c\">И</font>ису́се, Па́стырю мой, не погуби́ мене́́. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 3</font></b><br /><br />\n<font color=\"#aa2c2c\">С</font>и́лою свы́ше \nапо́столы облеки́й, Иису́се, во Иерусали́ме седя́щия, \nоблецы́ и мене́́, обнаже́ннаго от вся́каго благотворе́ния, \nтеплото́ю Ду́ха Свята́го Твоего́ и даждь ми с \nлюбо́вью пе́ти Тебе́: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 3</font></b><br /><br />\n<font color=\"#aa2c2c\">И</font>ме́яй бога́тство милосе́рдия, мытари́ и \nгре́шники, и неве́рныя призва́л еси́́, Иису́се; не \nпре́зри и мене́́ ны́не, подо́бнаго им, но, я́ко \nмногоце́нное ми́ро, приими́ песнь сию́: <br />\n\n<font color=\"#aa2c2c\">И</font>ису́се, си́ло непобеди́мая; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, ми́лосте безконе́чная. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, красото́ пресве́тлая; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, любы́ неизрече́нная. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́га Жива́го; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, поми́луй мя гре́шнаго. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, услы́ши мя в беззако́ниих зача́таго; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, очи́сти мя во гресе́х рожде́ннаго. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, научи́ мя непотре́бнаго; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, освети́ мя те́мнаго. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, очи́сти мя скве́рнаго; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, возведи́ мя блу́днаго. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 4</font></b><br /><br />\n<font color=\"#aa2c2c\">Б</font>у́рю внутрь име́яй помышле́ний \nсумни́тельных, Петр утопа́ше; узре́в же во пло́ти Тя \nсу́ща, Иису́се, и по вода́м ходя́ща, позна́ Тя Бо́га \nи́стиннаго и, ру́ку спасе́ния получи́в, рече́: <font color=\"#aa2c2c\">А</font>ллилу́ия. <br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 4</font></b><br /><br />\n<font color=\"#aa2c2c\">С</font>лы́ша слепы́й мимоходя́ща Тя, Го́споди, \nпуте́м вопия́ше: Иису́се, Сы́не Дави́дов, поми́луй мя! \nИ, призва́в, отве́рзл еси́́ о́чи его́. Просвети́ у́бо \nми́лостию Твое́ю о́чи мы́сленныя се́рдца и мене́́, \nвопию́ща Ти и глаго́люща:<br />\n\n<font color=\"#aa2c2c\">И</font>ису́се, вы́шних Созда́телю; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, ни́жних Искупи́телю. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, преиспо́дних потреби́телю; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, всея́ тва́ри украси́телю. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, души́ моея́ уте́шителю; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, ума́ моего́ просвети́телю.<br />\n<font color=\"#aa2c2c\">И</font>ису́се, се́рдца моего́ весе́лие; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, тела́ моего́ здра́вие. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Спа́се мой, спаси́ мя; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, све́те мой, просвети́ мя. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, му́ки вся́кия изба́ви мя; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, спаси́ мя, недосто́йнаго. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 5</font></b><br /><br />\n<font color=\"#aa2c2c\">Б</font>огото́чною Кро́вию я́коже искупи́л еси́ \nнас дре́вле от зако́нныя кля́твы, Иису́се, си́це изми́ \nнас от се́ти, е́юже змий запя́т ны страстьми́ плотски́ми \nи блу́дным наважде́нием, и злым уны́нием, вопию́щия Ти: \n<font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 5</font></b><br /><br />\n<font color=\"#aa2c2c\">В</font>и́девше о́троцы евре́йстии во о́бразе \nчелове́честем Созда́вшаго руко́ю челове́ка и Влады́ку \nразуме́вше Его́, потща́шася ве́твьми угоди́ти Ему́, \nоса́нна вопию́ще. Мы же песнь прино́сим Ти, глаго́люще: <br />\n\n<font color=\"#aa2c2c\">И</font>ису́се, Бо́же и́стинный; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Дави́дов. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Царю́ пресла́вный; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, А́гнче непоро́чный. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Па́стырю преди́вный; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, храни́телю во мла́дости мое́й. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, корми́телю во ю́ности мое́й; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, похвало́ в ста́рости мое́й. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, наде́ждо в сме́рти мое́й; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, живо́те по сме́рти мое́й. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, утеше́ние мое́ на суде́ Твое́м; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, жела́ние мое́, не посрами́ мене́ тогда́. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 6</font></b><br /><br />\n<font color=\"#aa2c2c\">П</font>ропове́дник богоно́сных веща́ние и глаго́лы \nисполня́я, Иису́се, на земли́ я́влься и с челове́ки \nНевмести́мый пожи́л еси́, и боле́зни на́ша подъя́л \nеси́; отню́дуже ра́нами Твои́ми мы исцеле́вше, пе́ти \nнавыко́хом: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 6</font></b><br /><br />\n<font color=\"#aa2c2c\">В</font>озсия́ вселе́нней просвеще́ние и́стины \nТвоея́, и отгна́ся лесть бесо́вская: и́доли бо, Спа́се \nнаш, не терпя́ще Твоея́ кре́пости, падо́ша. Мы же, \nспасе́ние получи́вше, вопие́м Ти:<br />\n\n<font color=\"#aa2c2c\">И</font>ису́се, и́стино, лесть отгоня́щая; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, све́те, превы́шший всех све́тлостей. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Царю́, премога́яй всех кре́пости; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Бо́же, пребыва́яй в ми́лости. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Хле́бе живо́тный, насы́ти мя а́лчущаго; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, исто́чниче ра́зума, напо́й мя жа́ждущаго. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, оде́ждо весе́лия, оде́й мя тле́ннаго; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, покро́ве ра́дости, покры́й мя, недосто́йнаго. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, пода́телю прося́щим, даждь ми плач за грехи́ моя́; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, обрете́ние и́щущим, обря́щи ду́шу мою́. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, отве́рзителю толку́щим, отве́рзи се́рдце мое́ окая́нное; \n<font color=\"#aa2c2c\">И</font>ису́се, Искупи́телю гре́шных, очи́сти беззако́ния моя́. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n",
        "AcafistIiSusuSladchaishemu2" to "\n\n<b><font color=\"#aa2c2c\">Кондак 7</font></b><br /><br />\n<font color=\"#aa2c2c\">Х</font>отя́ сокрове́нную та́йну от ве́ка \nоткры́ти, я́ко овча́ на заколе́ние веде́н был еси́, \nИису́се, и я́ко а́гнец пря́мо стригу́щаго его́ \nбезгла́сен, и яко́ Бог из ме́ртвых воскре́сл еси́ и \nсо сла́вою на небеса́ возне́слся еси́, и нас \nсовоздви́гл еси́, зову́щих: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 7</font></b><br /><br />\n<font color=\"#aa2c2c\">Д</font>и́вную показа́ тварь, явле́йся Творе́ц \nнам: без се́мене от Де́вы воплоти́ся; из гро́ба, \nпеча́ти не руши́в, воскре́се; и ко апо́столом, две́рем \nзатворе́нным, с пло́тию вни́де. Те́мже чудя́щеся, \nвоспои́м: <br />\n\n<font color=\"#aa2c2c\">И</font>ису́се, Сло́ве необыме́нный; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сло́ве несогляда́емый. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, си́ло непостижи́мая; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, му́дросте недомы́слимая. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Божество́ неопи́санное; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, госпо́дство неисче́тное. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, ца́рство непобеди́мое; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, влады́чество безконе́чное. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, кре́посте высоча́йшая; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, вла́сте ве́чная. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Тво́рче мой, уще́дри мя; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Спа́се мой, спаси́ мя. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 8</font></b><br /><br />\n<font color=\"#aa2c2c\">С</font>тра́нно Бо́га вочелове́чшася ви́дяще, устрани́мся \nсу́етнаго ми́ра и ум на Боже́ственная возложи́м. Сего́ \nбо ра́ди Бог на зе́млю сни́де, да нас на небеса́ \nвозведе́т, вопию́щих Ему́: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 8</b><br /><br />\n<font color=\"#aa2c2c\">В</font>есь бе в \nни́жних, и вы́шних ника́коже отступи́ Неисче́тный, егда́ \nво́лею нас ра́ди пострада́ и сме́ртию Свое́ю на́шу \nсмерть умертви́, и Воскресе́нием живо́т дарова́ пою́щим: <br />\n\n<font color=\"#aa2c2c\">И</font>ису́се, сла́досте серде́чная; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, кре́посте теле́сная. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, све́тлосте душе́вная; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, быстрото́ у́мная. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, ра́досте со́вестная; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, наде́ждо изве́стная. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, па́мяте предве́чная; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, похвало́ высо́кая. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, сла́во моя́ превознесе́нная; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, жела́ние мое́, не отри́ни мене́. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Па́стырю мой, взыщи́ мене́; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Спа́се мой, спаси́ мене́. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 9</font></b><br /><br />\n<font color=\"#aa2c2c\">В</font>се естество́ а́нгельское безпреста́ни \nсла́вит пресвято́е и́мя Твое́, Иису́се, на небеси́: \nСвят, Свят, Свят, вопию́ще; мы же, гре́шнии, на \nземли́ бре́нными устна́ми вопие́м: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 9</font></b><br /><br />\n<font color=\"#aa2c2c\">В</font>ети́я многовеща́нныя, я́коже ры́бы \nбезгла́сныя ви́дим о Тебе́, Иису́се, Спа́се наш: \nнедоуме́ют бо глаго́лати, ка́ко Бог непрело́жный и \nчелове́к соверше́нный пребыва́еши? Мы же, та́инству \nдивя́щеся, вопие́м ве́рно: <br />\n\n<font color=\"#aa2c2c\">И</font>ису́се, Бо́же предве́чный; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Царю́ ца́рствующих. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Влады́ко владе́ющих; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Судие́ живы́х и ме́ртвых. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, наде́ждо ненаде́жных; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, утеше́ние пла́чущих. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, сла́во ни́щих; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, не осуди́ мя по дело́м мои́м. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, очи́сти мя по ми́лости Твое́й; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, отжени́ от мене́ уны́ние. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, просвети́ моя́ мы́сли серде́чныя; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, даждь ми па́мять сме́ртную. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 10</font></b><br /><br />\n<font color=\"#aa2c2c\">С</font>пасти́ хотя́ мир, Восто́че восто́ком, к \nте́мному за́паду естеству́ на́шему прише́д, смири́лся еси́ \nдо сме́рти; те́мже превознесе́ся и́мя Твое́ па́че \nвся́каго и́мене, и от всех коле́н небе́сных и \nземны́х слы́шиши: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 10</font></b><br /><br />\n<font color=\"#aa2c2c\">Ц</font>арю́ Предве́чный, Уте́шителю, Христе́ и́стинный, \nочи́сти ны от вся́кия скве́рны, я́коже очи́стил еси́ \nде́сять прокаже́нных, и исцели́ ны, я́коже исцели́л \nеси́ сребролюби́вую ду́шу Закхе́а мытаря́, да вопие́м \nТи, во умиле́нии зову́ще:<br />\n\n<font color=\"#aa2c2c\">И</font>ису́се, сокро́вище нетле́нное; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, бога́тство неистощи́мое.<br />\n<font color=\"#aa2c2c\">И</font>ису́се, пи́ще кре́пкая; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, питие́ неисчерпа́емое. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, ни́щих одея́ние; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, вдов заступле́ние. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, си́рых защи́тниче; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, тружда́ющихся по́моще. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, стра́нных наста́вниче; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, пла́вающих ко́рмчий. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, бу́рных оти́шие; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Бо́же, воздви́гни мя па́дшаго. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 11</font></b><br /><br />\n<font color=\"#aa2c2c\">П</font>е́ние всеумиле́нное приношу́ Ти, недосто́йный, \nвопию́ Ти я́ко ханане́а: Иису́се, поми́луй мя; не \nдщерь бо, но плоть и́мам страстьми́ лю́те беся́щуюся \nи я́ростию пали́мую, и исцеле́ние даждь вопию́щу Ти: \n<font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 11</font></b><br /><br />\n<font color=\"#aa2c2c\">С</font>ветопода́тельна свети́льника су́щим во тьме \nнеразу́мия, пре́жде гоня́й Тя Па́вел, богоразу́мнаго \nгла́са си́лу внуши́ и душе́вную быстроту́ уясни́; си́це \nи мене́ те́мныя зе́ницы душе́вныя просвети́, зовуща:<br />\n \n<font color=\"#aa2c2c\">И</font>ису́се, Царю мой прекрепкий; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Боже мой преси́льный. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Го́споди мой пребезсме́ртный; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Созда́телю мой пресла́вный. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Наста́вниче мой предо́брый; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Па́стырю мой преще́дрый. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Влады́ко мой преми́лостивый; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Спа́се мой премилосе́рдый. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, просвети́ моя́ чу́вствия, потемне́нныя страстьми́; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, исцели́ мое́ те́ло, острупле́нное грехми́. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, очи́сти мой ум от по́мыслов су́етных; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, сохрани́ се́рдце мое́ от по́хотей лука́вых. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 12</font></b><br /><br />\n<font color=\"#aa2c2c\">Б</font>лагода́ть пода́ждь ми, всех долго́в \nреши́телю, Иису́се, и приими́ мя ка́ющася, я́коже \nприя́л еси́ Петра́, отве́ргшагося Тебе́, и призови́ \nмя, уныва́ющаго, я́коже дре́вле Па́вла, гоня́ща Тя, и \nуслы́ши мя, вопию́ща Ти: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 12</font></b><br /><br />\n<font color=\"#aa2c2c\">П</font>ою́ще Твое́ вочелове́чение, восхваля́ем Тя \nвси и ве́руем со Фомо́ю, я́ко Госпо́дь и Бог \nеси́, седя́й со Отце́м и хотя́й суди́ти живы́м и \nме́ртвым. Тогда́ у́бо сподо́би мя десна́го стоя́ния, \nвопию́щаго: <br />\n\n<font color=\"#aa2c2c\">И</font>ису́се, Царю́ предве́чный, поми́луй мя; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, цве́те благово́нный, облагоуха́й мя. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, теплото́ люби́мая, огре́й мя; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, хра́ме предве́чный, покры́й мя. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, оде́ждо све́тлая, украси́ мя; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, би́сере честны́й, осия́й мя. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, ка́меню драги́й, просвети́ мя; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, со́лнце пра́вды, освети́ мя. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, све́те святы́й, облиста́й мя; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, боле́зни душе́вныя и теле́сныя изба́ви мя. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, из руки́ сопроти́вныя изми́ мя; <br />\n<font color=\"#aa2c2c\">И</font>ису́се, огня́ неугаси́маго и про́чих ве́чных мук свободи́ мя. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 13</font></b><br /><br />\n<font color=\"#aa2c2c\">О</font>, Пресла́дкий и Всеще́дрый Иису́се! Приими́ \nны́не ма́лое моле́ние сие́ на́ше, я́коже прия́л еси́ \nвдови́цы две ле́пте, и сохрани́ достоя́ние Твое́ от \nвраг ви́димых и неви́димых, от наше́ствия иноплеме́нних, \nот неду́га и гла́да, от вся́кия ско́рби и \nсмертоно́сныя ра́ны, и гряду́щия изми́ му́ки всех, \nвопию́щих Ти: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br />\n\n\n<i><font color=\"#aa2c2c\">(Kондак читается трижды)</font></i><br /><br />\n\n\n<b><font color=\"#aa2c2c\">Икос 1</font></b><br /><br />\n<font color=\"#aa2c2c\">А́</font>нгелов Тво́рче и Го́споди Сил, отве́рзи \nми недоуме́нный ум и язы́к на похвалу́ пречи́стаго \nТвоего́ и́мене, я́коже глухо́му и гугни́вому дре́вле \nслух и язы́к отве́рзл еси́́, и, глаго́лаше, зовы́й \nтакова́я: <br />\n\n<font color=\"#aa2c2c\">И</font>ису́се пречу́дный, А́нгелов удивле́ние; <br />\n<font color=\"#aa2c2c\">И</font>ису́се преси́́льный, прароди́телей избавле́ние. <br />\n<font color=\"#aa2c2c\">И</font>ису́се пресла́дкий, патриа́рхов велича́ние; <br />\n<font color=\"#aa2c2c\">И</font>ису́се пресла́вный, царе́й укрепле́ние. <br />\n<font color=\"#aa2c2c\">И</font>ису́се прелюби́мый, проро́ков исполне́ние; <br />\n<font color=\"#aa2c2c\">И</font>ису́се преди́вный, му́чеников кре́посте. <br />\n<font color=\"#aa2c2c\">И</font>ису́се прети́хий, мона́хов ра́досте; <br />\n<font color=\"#aa2c2c\">И</font>ису́се преми́лостивый, пресви́теров сла́досте. <br />\n<font color=\"#aa2c2c\">И</font>ису́се премилосе́рдый, по́стников воздержа́ние; <br />\n<font color=\"#aa2c2c\">И</font>ису́се пресла́достный, преподо́бных ра́дование. <br />\n<font color=\"#aa2c2c\">И</font>ису́се пречестны́й, де́вственных целому́дрие; <br />\n<font color=\"#aa2c2c\">И</font>ису́се предве́чный, гре́шников спасе́ние. <br />\n<font color=\"#aa2c2c\">И</font>ису́се, Сы́не Бо́жий, поми́луй мя.<br /><br />\n\n\n<b><font color=\"#aa2c2c\">Кондак 1</font></b><br /><br />\n<font color=\"#aa2c2c\">В</font>озбра́нный Воево́до и Го́споди, а́да победи́телю, \nя́ко изба́влься от ве́чныя сме́рти, похва́льная воспису́ю \nТи, созда́ние и раб Твой; но, я́ко име́яй милосе́рдие \nнеизрече́нное, от вся́ких мя бед свободи́, зову́ща: <br />\n\n<font color=\"#aa2c2c\">И</font>ису́се,Сы́не Бо́жий, поми́луй мя.</p>\n<p> <br /><br />\n\n\n<b><font color=\"#aa2c2c\">Молитва</font></b><br /><br />\n<font color=\"#aa2c2c\">В</font>лады́ко Го́споди Иису́се Христе́ Бо́же \nмой, И́же неизрече́ннаго ра́ди Твоего́ человеколю́бия на \nконе́ц веко́в во плоть оболки́йся от Присноде́вы \nМари́и, сла́влю о мне Твое́ спаси́тельное промышле́ние, \nраб Твой, Влады́ко; песносло́влю Тя, я́ко Тебе́ ра́ди \nОтца́ позна́х; благословлю́ Тя, Его́же ра́ди и Дух \nСвяты́й в мир прии́де; покланя́юся Твое́й по пло́ти Пречи́стей \nМа́тери, такове́й стра́шней та́йне послужи́вшей; восхваля́ю \nТвоя́ А́нгельская ликостоя́ния, я́ко воспева́тели и \nслужи́тели Твоего́ вели́чествия; ублажа́ю Предте́чу Иоа́нна, \nТебе́ крести́вшаго, Го́споди; почита́ю и провозвести́вшия \nТя проро́ки; прославля́ю апосто́лы Твоя́ святыя; \nторжеству́ю же и му́ченики, свяще́нники же Твоя сла́влю; \nпоклоня́юся преподо́бным Твои́м, и вся Твоя́ пра́ведники \nпе́стунствую. Такова́го и толи́каго мно́гаго и неизрече́ннаго \nли́ка Боже́ственнаго в моли́тву привожду́ Тебе́, Всеще́дрому \nБо́гу, раб Твой, сего́ ра́ди прошу́ мои́м согреше́ниям проще́ния, \nе́же да́руй ми всех Твои́х ра́ди святы́х, изря́днее \nже святы́х Твои́х щедро́т, я́ко благослове́н еси́ во \nве́ки.<font color=\"#aa2c2c\"> А</font>ми́нь.<br /><br />",
        "acafistNikolayu" to "<h2><font color=\"#aa2c2c\">Акафист святителю Николаю Чудотворцу</font></h2><br /><br />\n\n<b><font color=\"#aa2c2c\">Тропарь, глас 4-й</font></b><br /><br />\n\n<font color=\"#aa2c2c\">П</font>ра́вило ве́ры и о́браз кро́тости, воздержа́ния учи́теля яви́ тя стаду твоему я́же веще́й и́стина: сего́ ра́ди стяжа́л еси́ смире́нием высо́кая, нището́ю бога́тая. О́тче священноначальниче Нико́лае, моли Христа́ Бо́га спасти́ся душа́м на́шым<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак, глас 3-й</font></b><br /><br />\n\n<font color=\"#aa2c2c\">В</font> Ми́рех, святе́, священнодействитель показа́лся е́си: Христо́во бо, преподо́бне, Ева́нгелие испо́лнив, положил ду́шу твою о лю́дех твоих, и спасл еси непови́нныя от смерти; сего́ ра́ди освяти́лся е́си, я́ко вели́кий таинник Бо́жия благода́ти.<br /><br />\n\n<h2><font color=\"#aa2c2c\">АКАФИСТ</font></h2><br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 1</font></b><br /><br />\n\n<font color=\"#aa2c2c\">В</font>озбра́нный Чудотво́рче и изря́дный уго́дниче Христо́в, ми́ру всему́ источа́яй \nмногоце́нное ми́лости ми́ро и неисчерпа́емое чуде́с мо́ре, восхваля́ю \nтя любо́вию, святи́телю Нико́лае: ты же, я́ко име́яй дерзнове́ние ко Го́споду, от \nвся́ких мя бед свободи́, да зову́ ти:<br /><br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 1</font></b><br /><br />\n\n<font color=\"#aa2c2c\">А́</font>нгела о́бразом, земна́го су́ща естество́м яви́ \nтебе́ всея́ тва́ри Созда́тель; благопло́дную бо добро́ту души́ твоея́ \nпрови́дев, преблаже́нне Нико́лае, научи́ всех вопи́ти тебе́ си́це:<br /><br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, от утро́бы ма́терния очище́нный<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nда́же до конца́ освяще́нный.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, рожде́нием свои́м роди́телей \nудиви́вый;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, си́лу душе́вную а́бие по рождестве́ яви́вый.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, са́де земли́ обетова́ния;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, цве́те Боже́ственнаго \nсажде́ния.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, лозо́ доброде́тельная виногра́да Христо́ва<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, дре́во чудото́чное рая́ Иису́сова.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, кри́не ра́йскаго \nпрозябе́ния;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, ми́ро Христо́ва благоуха́ния.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко \nтобо́ю отго́нится рыда́ние;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко тобо́ю прино́сится \nра́дование.<br />\n\n<font color=\"#aa2c2c\">р</font>адуйся, Николае, великий Чудотворче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 2</font></b><br /><br />\n\n<font color=\"#aa2c2c\">В</font>и́дяще твои́х мир излия́ние, богому́дре, \nпросвеща́емся душа́ми и телесы́, ди́внаго тя мирото́чца живоно́сна, \nНико́лае, разуме́юще: чудесы́ бо я́ко вода́ми, благода́тию Бо́жиею \nизлива́ющимися, напая́еши ве́рно вопию́щих к Бо́гу: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 2</font></b><br /><br />\n\n<font color=\"#aa2c2c\">Р</font>а́зум неуразуме́нный вразумля́я о Святе́й Тро́ице, \nбыл еси́ в Нике́и со святы́ми отцы́ побо́рник испове́дания \nПравосла́вныя ве́ры: ра́вна бо Отцу́ Сы́на испове́дал еси́, \nсоприсносу́щна и сопресто́льна, А́риа же безу́мнаго обличи́л еси́. \nСего́ ра́ди ве́рнии научи́шася воспева́ти тебе́:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, вели́кий благоче́стия сто́лпе;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nве́рных прибе́жища гра́де. <br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, тве́рдое Правосла́вия укрепле́ние; <br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, честно́е Пресвяты́я Тро́ицы носи́ло и похвале́ние.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, \nОтцу́ равноче́стна Сы́на пропове́давый;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, А́риа возбеси́вшагося \nот Собо́ра святы́х отгна́вый.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, о́тче, отце́в сла́вная \nкрасото́;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, всех богому́дрых прему́драя добро́то.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, \nо́гненная словеса́ испуща́яй;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, до́бре ста́до свое́ \nнаставля́яй.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко тобо́ю ве́ра утвержда́ется;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко \nтобо́ю ересь низлага́ется.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 3</font></b><br /><br />\n\n<font color=\"#aa2c2c\">С</font>и́лою, да́нною ти свы́ше, сле́зу вся́ку отъя́л еси́ \nот лица́ лю́те стра́ждущих, богоно́се о́тче Нико́лае: а́лчущим бо \nяви́лся еси́ корми́тель, в пучи́не морсте́й су́щим изря́дный \nправи́тель, неду́гующим исцеле́ние и всем всяк помо́щник показа́лся \nеси́, вопию́щим Бо́гу: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 3</font></b><br /><br />\n\n<font color=\"#aa2c2c\">И</font>ме́яше вои́стинну, о́тче Нико́лае, с небесе́ песнь \nтебе́ воспева́ема бы́ти, а не от земли́: ка́ко бо кто от челове́к \nвозмо́жет твоея́ святы́ни вели́чия пропове́дати? Но мы, любо́вию \nтвое́ю побежда́еми, вопие́м ти си́це:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, о́бразе а́гнцев и па́стырей;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nсвято́е очисти́лище нра́вов.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, доброде́телей вели́ких \nвмести́лище;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, святы́ни чи́стое и честно́е жили́ще.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, \nсвети́льниче всесве́тлый и вселюби́мый;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, све́те златоза́рный и \nнепоро́чный.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, досто́йный А́нгелов собесе́дниче;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nдо́брый челове́ков наста́вниче.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, пра́вило ве́ры благочести́выя; <br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, о́бразе кро́тости духо́вныя. <br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко тобо́ю от \nстрасте́й теле́сных избавля́емся;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко тобо́ю сла́достей \nдухо́вных исполня́емся.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 4</font></b><br /><br />\n\n<font color=\"#aa2c2c\">Б</font>у́ря недоуме́ния смуща́ет ми ум, ка́ко досто́йно \nесть пе́ти чудеса́ твоя́, блаже́нне Нико́лае; никто́же бо мо́жет я́ \nисчести́, а́ще бы и мно́ги язы́ки име́л и глаго́лати восхоте́л; но \nмы ди́вно Бо́гу, в тебе́ прославля́ющемуся, дерза́ем воспева́ти: \n<font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 4</font></b><br /><br />\n\n<font color=\"#aa2c2c\">С</font>лы́шаша, богому́дре Нико́лае, бли́жнии и да́льнии \nвели́чие чуде́с твои́х, я́ко по возду́ху ле́гкими благода́тными \nкрила́ми навы́кл еси́ су́щих в беда́х предваря́ти, ско́ро от тех \nизбавля́я всех, вопию́щих к тебе́ такова́я:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, избавле́ние от печа́ли;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, подая́ние \nблагода́ти.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, неча́емых зол прогони́телю;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, жела́емых \nблаги́х насади́телю.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, ско́рый уте́шителю в беде́ су́щих; <br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, стра́шный наказа́телю оби́дящих.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, чуде́с пучи́но, \nБо́гом излия́нная;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, зако́на Христо́ва скрижа́ли Бо́гом \nпи́санныя.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, кре́пкое па́дающих возведе́ние; <br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, пра́во \nстоя́щих утвержде́ние. <br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко тобо́ю вся́кая лесть обнажа́ется; <br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко тобо́ю вся́кая и́стина сбыва́ется.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 5</font></b><br /><br />\n\n<font color=\"#aa2c2c\">Б</font>оготе́чная звезда́ яви́лся еси́, наставля́я по мо́рю \nпла́вающих лю́те, и́мже смерть предстоя́ше вско́ре иногда́, а́ще не \nбы ты предста́л еси́ призыва́ющим тя в по́мощь, Чудотво́рче святы́й \nНико́лае; уже́ бо несты́дно бесо́м лета́ющим и погрузи́ти корабли́ \nхотя́щим запрети́в, отгна́л еси́ их, ве́рныя же научи́л еси́ \nспаса́ющему тобо́ю Бо́гу взыва́ти: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 5</font></b><br /><br />\n\n<font color=\"#aa2c2c\">В</font>и́деша отрокови́цы, на брак скве́рный нищеты́ ра́ди \nугото́ванныя, вели́кое твое́ к ни́щим милосе́рдие, преблаже́нне о́тче \nНико́лае, егда́ ста́рцу роди́телю их но́щию узельцы́ три зла́та \nтая́ся пода́л еси́, самаго́ со дще́рьми избавля́я от паде́ния \nгрехо́внаго. Того́ ра́ди слы́шиши от всех си́це:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, ми́лости превели́кия сокро́вище;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nпромышле́ния о лю́дех прия́телище.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, пи́ще и отра́до к тебе́ \nприбега́ющих;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, хле́бе неснеда́емый а́лчущих.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, \nбога́тство, бе́дне живу́щим на земли́ Бо́гом да́нное;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nвоздви́жение ско́рое убо́гих.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, бы́строе ни́щих услы́шание; <br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, скорбя́щих прия́тное попече́ние.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, трие́х дев \nнепоро́чный невести́телю;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, чистоты́ усе́рдный храни́телю. <br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, ненаде́жных наде́яние;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, всего́ ми́ра наслажде́ние.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 6</font></b><br /><br />\n\n<font color=\"#aa2c2c\">П</font>ропове́дует мир весь тебе́, преблаже́нне Нико́лае, \nско́раго в беда́х засту́пника, я́ко мно́гажды во еди́ном часе́ по \nземли́ путеше́ствующим и по мо́рю пла́вающим, предваря́я, \nпосо́бствуеши, ку́пно всех от злых сохраня́я, вопию́щих к Бо́гу: \n<font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 6</font></b><br /><br />\n\n<font color=\"#aa2c2c\">В</font>озсия́л еси́ свет живо́тный, избавле́ние нося́ \nвоево́дам, непра́ведную смерть прия́ти иму́щим, тебе́, до́брый па́стырю \nНико́лае, призыва́ющим, егда́ вско́ре я́влься во сне царе́ви, \nустраши́л еси́ его́, сих же неврежде́нных отпусти́ти повеле́л еси́. \nСего́ ра́ди с ни́ми ку́пно и мы благода́рственно вопие́м ти:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, усе́рдно призыва́ющим тя помога́яй; <br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, от непра́веднаго убие́ния избавля́яй. <br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, от ле́стныя \nсохраня́яй клеветы́;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, непра́ведныя разруша́яй сове́ты. <br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, \nрастерза́яй лжу я́ко паучи́ну;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, возноша́яй сла́вно и́стину. <br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, непови́нных от уз разреше́ние;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, и мертвеце́в \nоживле́ние.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, прояви́телю пра́вды;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, помрачи́телю \nнепра́вды.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко тобо́ю непови́ннии изба́влени от меча́; <br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко тобо́ю наслади́шася све́та.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 7</font></b><br /><br />\n\n<font color=\"#aa2c2c\">Х</font>отя́ богоху́льное ерети́ческое отгна́ти злосмра́дие, \nми́ро вои́стинну благово́нное, та́инственное яви́лся еси́, Нико́лае: \nлю́ди мире́йския упа́сл еси́ и весь мир свои́м благода́тным ми́ром \nиспо́лнил еси́. И от нас у́бо богоме́рзкое грехо́вное злосмра́дие \nотжени́, да благоприя́тно Бо́гу вопие́м: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n",
        "acafistNikolayu2" to "\n<b><font color=\"#aa2c2c\">Икос 7</font></b><br /><br />\n\n<font color=\"#aa2c2c\">Н</font>о́ваго тя Но́я, наста́вника ковче́га спаси́тельнаго \nразуме́ем, о́тче святы́й Нико́лае, бу́рю всех лю́тых разгоня́ющаго \nнаправле́нием свои́м, тишину́ же Боже́ственную принося́щаго вопию́щим \nтакова́я:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, обурева́емых ти́хое приста́нище;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nутопа́ющих изве́стное храни́лище.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, пла́вающих посреде́ пучи́н \nдо́брый ко́рмчий;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, треволне́ния морска́я уставля́ющий. <br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, превожде́ние су́щих в ви́хрех;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, согре́яние су́щих \nво мра́зех.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, сия́ние, ско́рбный мрак разгоня́ющее; <br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nсвети́ло, вся концы́ земли́ просвеща́ющее.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, от бе́здны \nгрехо́вныя челове́ки избавля́яй;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, в бе́здну а́дскую сатану́ \nвверга́яй.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко тобо́ю дерзнове́нно бе́здну милосе́рдия \nБо́жия призыва́ем;<br />\n\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко тобо́ю от пото́па гне́ва \nизба́вльшеся, мир с Бо́гом обрета́ем.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 8</font></b><br /><br />\n\n<font color=\"#aa2c2c\">С</font>тра́нное чу́до явля́ется притека́ющим к тебе́, \nблаже́нне Нико́лае, свяще́нная твоя́ це́рковь: в ней бо и ма́лое \nмоле́ние принося́ще, ве́лиих неду́гов прие́млем исцеле́ние, а́ще то́кмо \nпо Бо́зе упова́ние на тя возло́жим, ве́рно вопию́ще: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 8</font></b><br /><br />\n\n<font color=\"#aa2c2c\">В</font>есь еси́ всем вои́стинну помо́щник, богоно́се \nНико́лае, и собра́л еси́ вку́пе вся прибега́ющия к тебе́, я́ко \nсвободи́тель, пита́тель и врач ско́рый всем земны́м, на похвалу́ всех \nвоздвиза́я вопи́ти к тебе́ си́це:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, вся́ких исцеле́ний исто́чниче;<br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nлю́те стра́ждущим помо́щниче. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, заре́, сия́ющая в нощи́ \nгрехо́вней блужда́ющим; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, росо́ небото́чная в зно́и трудо́в \nсу́щим. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, подава́яй тре́бующим благострое́ние; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nуготовля́яй прося́щим изоби́лие. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, мно́гажды проше́ние \nпредваря́яй; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, ста́рым седи́нам си́лу обновля́яй.<br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, \nмно́гих заблу́ждших от пути́ и́стиннаго обличи́телю; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, та́ин \nБо́жиих ве́рный служи́телю.<br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко тобо́ю за́висть попира́ем; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко тобо́ю благонра́вное житие́ исправля́ем.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 9</font></b><br /><br />\n\n<font color=\"#aa2c2c\">В</font>ся́кия утоли́ боле́зни, вели́кий наш засту́пниче \nНико́лае, растворя́я благода́тная врачева́ния, услажда́ющая ду́ши на́ша, \nсердца́ же веселя́щая всех усе́рдно к по́мощи твое́й притека́ющих, \nБо́гу же вопию́щих: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 9</font></b><br /><br />\n\n<font color=\"#aa2c2c\">В</font>ети́я суему́дренныя нечести́вых ви́дим тобо́ю \nпосра́мленныя, богому́дре о́тче Нико́лае: А́риа бо ху́льника, разделя́юща \nБожество́, и Саве́ллия, смеша́юща Святу́ю Тро́ицу, препре́л, нас же \nво Правосла́вии укрепи́л еси́. Сего́ ра́ди вопие́м ти си́це:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, щи́те, защища́яй благоче́стие; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nмечу́, посеца́яй злоче́стие. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, учи́телю Боже́ственных веле́ний; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, губи́телю богопроти́вных уче́ний. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, ле́ствице, Бо́гом \nутвержде́нная, е́юже восхо́дим к небеси́; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, покро́ве, Бо́гом \nзда́нный, и́мже покрыва́ются мно́зи. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, нему́дрых умудри́вый \nтвои́ми словесы́; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, лени́вых подви́гнувый твои́ми нра́вы. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, све́тлосте за́поведей Бо́жиих неугаси́мая; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, луче́ \nоправда́ний Госпо́дних пресве́тлая. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко уче́нием твои́м \nсокруша́ются ерети́ческия главы́; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко тобо́ю ве́рнии \nсподобля́ются сла́вы.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 10</font></b><br /><br />\n\n<font color=\"#aa2c2c\">С</font>пасти́ хотя́ ду́шу, плоть твою́ ду́хови покори́л \nеси́ вои́стинну, о́тче наш Нико́лае, молча́ньми бо пре́жде и боре́ньми \nс по́мыслы, дея́нию богомы́слие приложи́л еси́, богомы́слием же ра́зум \nсоверше́н стяжа́л еси́, и́мже дерзнове́нно с Бо́гом и А́нгелы \nбесе́довал еси́, всегда́ вопию́щи: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 10</font></b><br /><br />\n\n<font color=\"#aa2c2c\">С</font>тена́ еси́ похваля́ющим, преблаже́нне, чудеса́ твоя́ \nи всем к заступле́нию твоему́ прибега́ющим; те́мже и нас, в \nдоброде́тели убо́гих, от нищеты́, напа́сти, неду́гов и нужд разли́чных \nсвобожда́й, вопию́щих ти с любо́вию такова́я:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, от убо́жества ве́чнаго изыма́яй; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nбога́тство нетле́нное подава́яй. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, бра́шно неги́блющее а́лчущим \nпра́вды; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, питие́ неисчерпа́емое жа́ждущим жи́зни. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, от \nмятежа́ и бра́ни соблюда́яй; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, от уз и плене́ния свобожда́яй. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, пресла́вный в беда́х засту́пниче; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, превели́кий в \nнапа́стех защи́тниче. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, мно́гих от поги́бели исхи́тивый; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, безчи́сленных неврежде́нно сохрани́вый. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко тобо́ю \nлю́тыя сме́рти гре́шнии избега́ют; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко тобо́ю жизнь ве́чную \nка́ющиися получа́ют.<br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 11</font></b><br /><br />\n\n<font color=\"#aa2c2c\">П</font>е́ние Пресвяте́й Тро́ице па́че ины́х прине́сл еси́, \nпреблаже́нне Нико́лае, умо́м, сло́вом и де́лом: мно́гим бо испыта́нием \nправове́рная повеле́ния уясни́л еси́, ве́рою, наде́ждою и любо́вию \nнаставля́я нас в Тро́ице Еди́ному Бо́гу воспева́ти: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 11</font></b><br /><br />\n\n<font color=\"#aa2c2c\">С</font>ветоза́рную лучу́ во мра́це жития́ су́щим \nнеугаси́мую ви́дим тя, Бо́гом избра́нне о́тче Нико́лае: с \nневеще́ственными бо а́нгельскими све́ты бесе́дуеши о несозда́нном \nТро́ическом Све́те, ве́рных же ду́ши просвеща́еши, вопию́щих ти \nтакова́я:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, озаре́ние Трисо́лнечнаго Све́та; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nденни́це незаходи́маго Со́лнца. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, свеще́, Боже́ственным \nпла́менем возжже́нная; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко угаси́л еси́ бесо́вский пла́мень \nнече́стия. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, све́тлое правове́рия пропове́дание; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nдоброзра́чное све́та ева́нгельскаго сия́ние. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, мо́лние, е́реси \nпожига́ющая; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, гро́ме, устраша́ющий соблазня́ющия. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, \nи́стиннаго научи́телю ра́зума; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, та́инственнаго изъяви́телю \nума́. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко тобо́ю попра́ся поклоне́ние тва́ри; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nя́ко тобо́ю научи́хомся поклоня́тися Творцу́ в Тро́ице.<br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 12</font></b><br /><br />\n\n<font color=\"#aa2c2c\">Б</font>лагода́ть, да́нную ти от Бо́га, све́дущии, \nра́дующеся твою́ па́мять пра́зднуем по до́лгу, пресла́вный о́тче \nНико́лае, и к чу́дному заступле́нию твоему́ вседу́шно притека́ем; \nпресла́вных же твои́х дея́ний, я́ко песка́ морска́го и мно́жества \nзве́зднаго исчести́ не могу́ще, недоуме́нием объя́ти бы́вше, вопие́м к \nБо́гу: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 12</font></b><br /><br />\n\n<font color=\"#aa2c2c\">П</font>ою́ще твоя́ чудеса́, восхваля́ем тя, всехва́льне \nНико́лае: в тебе́ бо Бог, в Тро́ице прославля́емый, ди́вно \nпросла́вися. Но а́ще и попремно́гу соста́вленныя от души́ псалмы́ и \nпе́сни прино́сим ти, Чудотво́рче святы́й, ничто́же твори́м ра́вно \nдарова́нию чуде́с твои́х, и́мже удивля́ющеся, вопие́м к тебе́ такова́я:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Царя́ ца́рствующих и Го́спода \nгоспо́дствующих служи́телю; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, служи́телей Его́ небе́сных \nсожи́телю. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, лю́дем ве́рным поможе́ние; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, ро́да \nхристиа́нскаго возвыше́ние. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, побе́ды тезоимени́тый; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nвенцено́сче нарочи́тый. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, всех доброде́телей зерца́ло; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nвсех притека́ющих к тебе́ кре́пкое забра́ло. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, по Бо́зе и Богоро́дице \nвсе на́ше упова́ние; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, теле́с на́ших здра́вие и душ \nспасе́ние. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко тобо́ю от ве́чныя сме́рти свобожда́емся; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко тобо́ю безконе́чныя жи́зни сподобля́емся.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 13</font></b><br /><br />\n\n<font color=\"#aa2c2c\">О</font> пресвяты́й и пречу́дный о́тче Нико́лае, утеше́ние \nвсех скорбя́щих, ны́нешнее на́ше приими́ приноше́ние и от гее́нны \nизба́витися нам Го́спода умоли́ богоприя́тным твои́м хода́тайством, да \nс тобо́ю воспева́ем: <font color=\"#aa2c2c\">А</font>ллилу́ия.<br />\n\n<i><font color=\"#aa2c2c\">Этот кондак читается трижды</font></i><br /><br />\n\n<b><font color=\"#aa2c2c\">Икос 1</font></b><br /><br />\n\n<font color=\"#aa2c2c\">А́</font>нгела о́бразом, земна́го су́ща естество́м яви́ \nтебе́ всея́ тва́ри Созда́тель; благопло́дную бо добро́ту души́ твоея́ \nпрови́дев, преблаже́нне Нико́лае, научи́ всех вопи́ти тебе́ си́це:<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, от утро́бы ма́терния очище́нный; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, \nда́же до конца́ освяще́нный. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, рожде́нием свои́м роди́телей \nудиви́вый; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, си́лу душе́вную а́бие по рождестве́ яви́вый. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, са́де земли́ обетова́ния; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, цве́те Боже́ственнаго сажде́ния. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, лозо́ доброде́тельная виногра́да Христо́ва; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, дре́во \nчудото́чное рая́ Иису́сова. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, кри́не ра́йскаго прозябе́ния; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, ми́ро Христо́ва благоуха́ния. <br />\n<font color=\"#aa2c2c\">Р</font>а́дуйся, я́ко тобо́ю \nотго́нится рыда́ние; <br />\n<font color=\"#aa2c2c\">р</font>а́дуйся, я́ко тобо́ю прино́сится ра́дование.<br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Кондак 1</font></b><br /><br />\n\n<font color=\"#aa2c2c\">В</font>озбра́нный Чудотво́рче и изря́дный уго́дниче Христо́в, ми́ру всему́ источа́яй \nмногоце́нное ми́лости ми́ро и неисчерпа́емое чуде́с мо́ре, восхваля́ю \nтя любо́вию, святи́телю Нико́лае: ты же, я́ко име́яй дерзнове́ние ко Го́споду, от \nвся́ких мя бед свободи́, да зову́ ти:<br /><br />\n\n<font color=\"#aa2c2c\">Р</font>а́дуйся, Нико́лае, вели́кий Чудотво́рче.<br /><br />\n\n<b><font color=\"#aa2c2c\">Молитва</font></b><br /><br />\n\n<font color=\"#aa2c2c\">О</font> всесвяты́й Нико́лае, уго́дниче преизря́дный \nГоспо́день, те́плый наш засту́пниче, и везде́ в ско́рбех ско́рый \nпомо́щниче! Помози́ ми, гре́шному и уны́лому, в настоя́щем сем \nжитии́, умоли́ Го́спода Бо́га дарова́ти ми оставле́ние всех мои́х \nгрехо́в, ели́ко согреши́х от ю́ности моея́, во всем житии́ мое́м, \nде́лом, сло́вом, помышле́нием и все́ми мои́ми чу́вствы; и во исхо́де \nдуши́ моея́ помози́ ми, окая́нному, умоли́ Го́спода Бо́га, всея́ \nтва́ри Соде́теля, изба́вити мя возду́шных мыта́рств и ве́чнаго \nмуче́ния, да всегда́ прославля́ю Отца́ и Сы́на и Свята́го Ду́ха и \nтвое́ ми́лостивное предста́тельство, ны́не и при́сно и во ве́ки \nвеко́в. <font color=\"#aa2c2c\">А</font>ми́нь.<br /><br />",
